def _bash_assign_literal(var_name: str, value: str) -> str:
    """Assign a value to a bash variable via a quoted heredoc (no shell expansion)."""
    name = var_name.strip()
    if not name.isidentifier():
        raise ValueError(f"invalid bash variable name: {var_name!r}")
    delimiter = "REBASE_LITERAL_EOF"
    while delimiter in value:
        delimiter = f"_{delimiter}_"
    return f"read -r {name} <<'{delimiter}'\n{value}\n{delimiter}"


